insert into public.knowledge_entries
  (type, title, body, category, tags, source_type, source_id, source_title, status, confidence, created_by)
values
('term','설명의무','보험회사와 보험모집 종사자가 계약 체결을 권유할 때 보험료·보장내용·해지환급금 등 중요한 사항을 일반금융소비자가 이해할 수 있도록 설명해야 하는 의무.','의무',array['설명의무'],'cycle1_error_fix','cycle1_fix','상법 제638조의3·금융소비자보호법 제19조','ai_draft','high','admin'),
('term','후유장해','상해(재해)를 직접 원인으로 치료 후에도 신체에 남은 영구적인 기능 상실. 약관 장해분류표의 지급률에 따라 보험금을 산정하며 질병 후유장해와 구분된다.','보장',array['후유장해','장해'],'cycle1_error_fix','cycle1_fix','보험업감독업무시행세칙 별표(장해분류표)','ai_draft','high','admin'),
('term','뇌졸중진단비','약관에서 뇌졸중(한국표준질병사인분류 I60~I66)으로 진단확정될 때 지급하는 진단비. 뇌혈관질환(I60~I69)보다 보장범위가 좁으며 구체 범위는 상품 약관에 따른다.','보장',array['뇌졸중진단비','뇌졸중'],'cycle1_error_fix','cycle1_fix','한국표준질병사인분류(KCD)·상품약관','ai_draft','high','admin'),
('term','재해보험','급격하고 우연한 외래의 사고(재해)를 보장하는 인보험으로 사실상 상해보험(상해담보)에 해당한다. 재물 대상의 농업재해보험 등과는 다른 용어.','상품',array['재해보험','상해담보'],'cycle1_error_fix','cycle1_fix','생명보험 표준약관 재해분류표','ai_draft','medium','admin'),
('term','BMI','체질량지수로 체중(kg)을 키(m)의 제곱으로 나눈 값. 대한비만학회 기준 저체중 18.5 미만·정상 18.5~22.9·비만 전단계 23~24.9·비만 25 이상. 보험 인수에서 비만도 평가 지표로 쓰이며 적용 기준값은 상품에 따라 다르다.','인수',array['BMI','체질량지수','비만도'],'cycle1_error_fix','cycle1_fix','대한비만학회 비만 진료지침','ai_draft','high','admin'),
('term','직업급수','상해위험도에 따라 직업을 나눈 등급. 손해보험은 1~3급 또는 1~4급 등 사별 체계로 운영되며 위험이 높을수록 보험료가 가산되거나 인수가 제한된다.','인수',array['직업급수','직업등급'],'cycle1_error_fix','cycle1_fix','보험개발원 직업위험등급·사별 인수지침','ai_draft','medium','admin'),
('term','연기','언더라이팅 결과의 하나로, 피보험자의 현재 건강상태·치료 이력 등을 이유로 일정 기간 청약 인수를 미루는 처리. 보험금 지급 보류와는 다르다.','인수',array['연기','인수연기'],'cycle1_error_fix','cycle1_fix','사별 언더라이팅 지침','ai_draft','medium','admin'),
('term','역선택','위험이 높은 사람일수록 보험에 가입하려는 경향이 강해, 정보 비대칭으로 보험단체의 위험이 평균보다 높아지는 현상. 허위 고지(고지의무 위반)와는 구분된다.','인수',array['역선택','정보비대칭'],'cycle1_error_fix','cycle1_fix','보험개발원·보험학 표준','ai_draft','high','admin'),
('term','참조요율','보험개발원이 산출해 제공하는 참고용 요율. 과거 의무사용이던 참조순보험요율 제도는 폐지되어 현재는 보험사가 이를 참고해 자율적으로 요율을 산출한다.','제도',array['참조요율','참조순보험요율'],'cycle1_error_fix','cycle1_fix','보험업법(요율산출)·보험개발원','ai_draft','high','admin'),
('term','불완전판매','보험모집 과정에서 중요사항을 제대로 설명·확인하지 않아 소비자가 충분히 이해하지 못한 채 계약이 체결되는 부실 판매 행위. 그 결과를 측정한 불완전판매비율과는 구분된다.','판매',array['불완전판매'],'cycle1_error_fix','cycle1_fix','금융소비자보호법·금감원 불완전판매비율 공시','ai_draft','high','admin'),
('term','적정성원칙','일반금융소비자가 권유 없이 청약하는 상품이 소비자의 재산·연령·거래목적 등에 비추어 적정하지 않으면 그 사실을 알려야 하는 의무. 권유 시의 적합성원칙과 구분된다.','판매',array['적정성원칙'],'cycle1_error_fix','cycle1_fix','금융소비자보호법 제18조','ai_draft','high','admin'),
('term','법인보험대리점','보험회사를 위하여 보험계약 체결을 대리하는 법인 형태의 보험대리점(GA 포함). 독립적으로 중개하는 보험중개사와 구분된다.','판매',array['법인보험대리점','GA'],'cycle1_error_fix','cycle1_fix','보험업법 제2조·제87조','ai_draft','high','admin'),
('term','승환계약','기존 보험계약을 부당하게 소멸시키고 새 계약을 청약하게 하거나 그 반대로 하는 행위(부당 승환). 적립금을 옮기는 계약전환과는 다르다.','판매',array['승환계약','부당승환'],'cycle1_error_fix','cycle1_fix','보험업법 제97조','ai_draft','high','admin'),
('term','손해사정사','보험사고로 인한 손해액과 보험금을 사정하는 전문자격자. 자격시험은 금융감독원장이 실시하고 등록은 금융위원회 소관이다.','민원',array['손해사정사'],'cycle1_error_fix','cycle1_fix','보험업법 제186조','ai_draft','high','admin'),
('term','보험자대위','보험회사가 보험금을 지급한 뒤 피보험자가 제3자(가해자 등)에게 갖는 권리나 보험목적물에 대한 권리를 취득하는 것. 민법상 대위변제와 다르므로 보험에서는 보험자대위가 정확한 용어.','민원',array['보험자대위','대위변제','청구권대위','잔존물대위'],'cycle1_error_fix','cycle1_fix','상법 제681조·제682조','ai_draft','high','admin'),
('term','비례보상','일부보험은 보험가입금액이 보험가액보다 작을 때 그 비율만큼 손해를 보상하고, 중복보험은 여러 계약의 보험금액 합계가 보험가액을 넘을 때 보험금액 비율로 안분 보상한다. 둘은 구분된다.','보장',array['비례보상','일부보험','중복보험'],'cycle1_error_fix','cycle1_fix','상법 제674조·제672조','ai_draft','high','admin'),
('term','배당','유배당 보험에서 보험회사가 이자율차·위험률차·사업비차 등에서 생긴 잉여를 계약자에게 돌려주는 계약자배당금.','제도',array['배당','계약자배당','유배당'],'cycle1_error_fix','cycle1_fix','보험업감독규정','ai_draft','medium','admin'),
('term','피보험이익','보험목적에 대해 피보험자가 갖는 경제적 이해관계(손해보험의 보험대상). 이를 금전으로 평가한 가액이 보험가액이며 보상의 최고한도가 된다.','계약',array['피보험이익','보험가액'],'cycle1_error_fix','cycle1_fix','상법 제668조·제670조','ai_draft','high','admin'),
('term','보험금 지급기한','보험회사는 청구서류 접수일부터 통상 3영업일 안에 보험금을 지급하며, 지급사유 조사·확인이 필요하면 약관에서 정한 기간(최장 30영업일) 안에 지급한다.','청구',array['보험금지급기한','지급기일'],'cycle1_error_fix','cycle1_fix','생명보험·질병상해보험 표준약관','ai_draft','high','admin'),
('term','휴면보험금','소멸시효가 지났으나 계약자·수익자가 찾아가지 않은 보험금. 시효 완성 후에도 ''내보험찾아줌'' 등을 통해 청구·수령할 수 있다.','청구',array['휴면보험금','내보험찾아줌'],'cycle1_error_fix','cycle1_fix','서민금융진흥원·생명보험협회','ai_draft','high','admin'),
('term','우대특약','건강상태·계약조건 등 일정 요건을 충족하면 보험료를 할인해 주는 특약. 할인율·요건은 상품 약관에 따른다.','상품',array['우대특약','보험료할인'],'cycle1_error_fix','cycle1_fix','사별 상품약관','ai_draft','medium','admin');
